using System;using System.Threading;using System.Threading.Tasks;namespace BgCommon;/// <summary>/// 异步操作辅助类，提供将同步操作转换为异步任务以及处理回调风格异步任务的工具方法./// </summary>public static class AsyncHelper{    /// <summary>    /// 在线程池上异步执行无参数的同步函数.    /// </summary>    /// <typeparam name="T">返回结果的类型.</typeparam>    /// <param name="syncAction">要执行的同步委托.</param>    /// <param name="cancellationToken">用于观察取消请求的取消令牌.</param>    /// <returns>一个表示异步操作的任务，其结果为执行函数的返回值.</returns>    public static Task<T?> OnAsync<T>(Func<T?> syncAction, CancellationToken cancellationToken = default)    {        // 验证参数        ArgumentNullException.ThrowIfNull(syncAction, nameof(syncAction));        // 将同步操作派发至线程池执行        return Task.Run(syncAction, cancellationToken);    }    /// <summary>    /// 在线程池上异步执行带有一个参数的同步函数.    /// </summary>    /// <typeparam name="T1">输入参数的类型.</typeparam>    /// <typeparam name="T">返回结果的类型.</typeparam>    /// <param name="doAction">要执行的同步函数委托.</param>    /// <param name="t1">传入函数的第一个参数.</param>    /// <param name="cancellationToken">用于观察取消请求的取消令牌.</param>    /// <returns>异步任务结果.</returns>    public static Task<T?> OnAsync<T1, T>(Func<T1?, T?> doAction, T1? t1, CancellationToken cancellationToken = default)    {        // 验证参数        ArgumentNullException.ThrowIfNull(doAction, nameof(doAction));        // 包装为无参委托并分派执行        return Task.Run(() => doAction(t1), cancellationToken);    }    /// <summary>    /// 在线程池上异步执行带有两个参数的同步函数.    /// </summary>    /// <typeparam name="T1">第一个参数类型.</typeparam>    /// <typeparam name="T2">第二个参数类型.</typeparam>    /// <typeparam name="T">返回结果类型.</typeparam>    /// <param name="doAction">要执行的同步函数委托.</param>    /// <param name="t1">第一个参数值.</param>    /// <param name="t2">第二个参数值.</param>    /// <param name="cancellationToken">用于观察取消请求的取消令牌.</param>    /// <returns>异步任务结果.</returns>    public static Task<T?> OnAsync<T1, T2, T>(Func<T1?, T2?, T?> doAction, T1? t1, T2? t2, CancellationToken cancellationToken = default)    {        // 验证参数        ArgumentNullException.ThrowIfNull(doAction, nameof(doAction));        // 包装并分派执行        return Task.Run(() => doAction(t1, t2), cancellationToken);    }    /// <summary>    /// 在线程池上异步执行带有三个参数的同步函数.    /// </summary>    /// <typeparam name="T1">参数1类型.</typeparam>    /// <typeparam name="T2">参数2类型.</typeparam>    /// <typeparam name="T3">参数3类型.</typeparam>    /// <typeparam name="T">返回结果类型.</typeparam>    /// <param name="doAction">要执行的同步函数委托.</param>    /// <param name="t1">参数1值.</param>    /// <param name="t2">参数2值.</param>    /// <param name="t3">参数3值.</param>    /// <param name="cancellationToken">用于观察取消请求的取消令牌.</param>    /// <returns>异步任务结果.</returns>    public static Task<T?> OnAsync<T1, T2, T3, T>(Func<T1?, T2?, T3?, T?> doAction, T1? t1, T2? t2, T3? t3, CancellationToken cancellationToken = default)    {        // 验证参数        ArgumentNullException.ThrowIfNull(doAction, nameof(doAction));        // 包装并分派执行        return Task.Run(() => doAction(t1, t2, t3), cancellationToken);    }    /// <summary>    /// 在线程池上异步执行带有四个参数的同步函数.    /// </summary>    /// <typeparam name="T1">参数1类型.</typeparam>    /// <typeparam name="T2">参数2类型.</typeparam>    /// <typeparam name="T3">参数3类型.</typeparam>    /// <typeparam name="T4">参数4类型.</typeparam>    /// <typeparam name="T">返回结果类型.</typeparam>    /// <param name="doAction">要执行的同步函数委托.</param>    /// <param name="t1">参数1值.</param>    /// <param name="t2">参数2值.</param>    /// <param name="t3">参数3值.</param>    /// <param name="t4">参数4值.</param>    /// <param name="cancellationToken">用于观察取消请求的取消令牌.</param>    /// <returns>异步任务结果.</returns>    public static Task<T?> OnAsync<T1, T2, T3, T4, T>(Func<T1?, T2?, T3?, T4?, T?> doAction, T1? t1, T2? t2, T3? t3, T4? t4, CancellationToken cancellationToken = default)    {        // 验证参数        ArgumentNullException.ThrowIfNull(doAction, nameof(doAction));        // 包装并分派执行        return Task.Run(() => doAction(t1, t2, t3, t4), cancellationToken);    }    /// <summary>    /// 在线程池上异步执行带有五个参数的同步函数.    /// </summary>    /// <typeparam name="T1">参数类型1.</typeparam>    /// <typeparam name="T2">参数类型2.</typeparam>    /// <typeparam name="T3">参数类型3.</typeparam>    /// <typeparam name="T4">参数类型4.</typeparam>    /// <typeparam name="T5">参数类型5.</typeparam>    /// <typeparam name="T">返回类型.</typeparam>    /// <param name="doAction">要执行的同步函数委托.</param>    /// <param name="t1">参数1.</param>    /// <param name="t2">参数2.</param>    /// <param name="t3">参数3.</param>    /// <param name="t4">参数4.</param>    /// <param name="t5">参数5.</param>    /// <param name="cancellationToken">用于观察取消请求的取消令牌.</param>    /// <returns>异步任务结果.</returns>    public static Task<T?> OnAsync<T1, T2, T3, T4, T5, T>(Func<T1?, T2?, T3?, T4?, T5?, T?> doAction, T1? t1, T2? t2, T3? t3, T4? t4, T5? t5, CancellationToken cancellationToken = default)    {        // 验证参数        ArgumentNullException.ThrowIfNull(doAction, nameof(doAction));        // 包装并分派执行        return Task.Run(() => doAction(t1, t2, t3, t4, t5), cancellationToken);    }    /// <summary>    /// 扩展方法：在线程池上异步执行指定的同步 Action.    /// </summary>    /// <param name="syncAction">要异步执行的同步委托.</param>    /// <param name="cancellationToken">用于观察取消请求的取消令牌.</param>    /// <returns>一个表示异步操作的任务.</returns>    public static Task OnAsync(this Action syncAction, CancellationToken cancellationToken = default)    {        // 验证参数        ArgumentNullException.ThrowIfNull(syncAction, nameof(syncAction));        // 将 Action 分派至线程池        return Task.Run(syncAction, cancellationToken);    }    /// <summary>    /// 扩展方法：将一个无参数的回调风格动作转换为 Task.    /// </summary>    /// <param name="doAction">接收任务完成源的操作委托.</param>    /// <param name="cancellationToken">用于观察取消请求的取消令牌.</param>    /// <returns>一个表示异步操作的任务.</returns>    public static Task<bool> OnAsync(this Action<TaskCompletionSource<bool>> doAction, CancellationToken cancellationToken = default)    {        return CreateTaskFromAction<bool>(taskSource => doAction(taskSource), cancellationToken);    }    /// <summary>    /// 扩展方法：将一个带有一个参数的回调风格动作转换为 Task.    /// </summary>    /// <typeparam name="T1">参数1类型.</typeparam>    /// <param name="doAction">操作委托.</param>    /// <param name="t1">参数1值.</param>    /// <param name="cancellationToken">取消令牌.</param>    /// <returns>异步任务.</returns>    public static Task<bool> OnAsync<T1>(this Action<TaskCompletionSource<bool>, T1?> doAction, T1? t1, CancellationToken cancellationToken = default)    {        return CreateTaskFromAction<bool>(taskSource => doAction(taskSource, t1), cancellationToken);    }    /// <summary>    /// 扩展方法：将一个带有两个参数的回调风格动作转换为 Task.    /// </summary>    /// <typeparam name="T1">参数1类型.</typeparam>    /// <typeparam name="T2">参数2类型.</typeparam>    /// <param name="doAction">操作委托.</param>    /// <param name="t1">参数1值.</param>    /// <param name="t2">参数2值.</param>    /// <param name="cancellationToken">取消令牌.</param>    /// <returns>异步任务.</returns>    public static Task<bool> OnAsync<T1, T2>(this Action<TaskCompletionSource<bool>, T1?, T2?> doAction, T1? t1, T2? t2, CancellationToken cancellationToken = default)    {        return CreateTaskFromAction<bool>(taskSource => doAction(taskSource, t1, t2), cancellationToken);    }    /// <summary>    /// 扩展方法：将一个带有三个参数的回调风格动作转换为 Task.    /// </summary>    /// <typeparam name="T1">参数1类型.</typeparam>    /// <typeparam name="T2">参数2类型.</typeparam>    /// <typeparam name="T3">参数3类型.</typeparam>    /// <param name="doAction">操作委托.</param>    /// <param name="t1">参数1.</param>    /// <param name="t2">参数2.</param>    /// <param name="t3">参数3.</param>    /// <param name="cancellationToken">取消令牌.</param>    /// <returns>异步任务.</returns>    public static Task<bool> OnAsync<T1, T2, T3>(this Action<TaskCompletionSource<bool>, T1?, T2?, T3?> doAction, T1? t1, T2? t2, T3? t3, CancellationToken cancellationToken = default)    {        return CreateTaskFromAction<bool>(taskSource => doAction(taskSource, t1, t2, t3), cancellationToken);    }    /// <summary>    /// 扩展方法：将一个带有四个参数的回调风格动作转换为 Task.    /// </summary>    /// <typeparam name="T1">参数类型1.</typeparam>    /// <typeparam name="T2">参数类型2.</typeparam>    /// <typeparam name="T3">参数类型3.</typeparam>    /// <typeparam name="T4">参数类型4.</typeparam>    /// <param name="doAction">操作委托.</param>    /// <param name="t1">参数1.</param>    /// <param name="t2">参数2.</param>    /// <param name="t3">参数3.</param>    /// <param name="t4">参数4.</param>    /// <param name="cancellationToken">取消令牌.</param>    /// <returns>异步任务.</returns>    public static Task<bool> OnAsync<T1, T2, T3, T4>(this Action<TaskCompletionSource<bool>, T1?, T2?, T3?, T4?> doAction, T1? t1, T2? t2, T3? t3, T4? t4, CancellationToken cancellationToken = default)    {        return CreateTaskFromAction<bool>(taskSource => doAction(taskSource, t1, t2, t3, t4), cancellationToken);    }    /// <summary>    /// 扩展方法：将一个带有五个参数的回调风格动作转换为 Task.    /// </summary>    /// <typeparam name="T1">参数类型1.</typeparam>    /// <typeparam name="T2">参数类型2.</typeparam>    /// <typeparam name="T3">参数类型3.</typeparam>    /// <typeparam name="T4">参数类型4.</typeparam>    /// <typeparam name="T5">参数类型5.</typeparam>    /// <param name="doAction">操作委托.</param>    /// <param name="t1">参数1.</param>    /// <param name="t2">参数2.</param>    /// <param name="t3">参数3.</param>    /// <param name="t4">参数4.</param>    /// <param name="t5">参数5.</param>    /// <param name="cancellationToken">取消令牌.</param>    /// <returns>异步任务.</returns>    public static Task<bool> OnAsync<T1, T2, T3, T4, T5>(this Action<TaskCompletionSource<bool>, T1?, T2?, T3?, T4?, T5?> doAction, T1? t1, T2? t2, T3? t3, T4? t4, T5? t5, CancellationToken cancellationToken = default)    {        return CreateTaskFromAction<bool>(taskSource => doAction(taskSource, t1, t2, t3, t4, t5), cancellationToken);    }    /// <summary>    /// 核心辅助方法：从外部动作创建异步任务，并统一处理取消和异常逻辑.    /// </summary>    /// <typeparam name="T">任务返回结果的类型.</typeparam>    /// <param name="action">封装了 TaskCompletionSource 操作的委托.</param>    /// <param name="cancellationToken">用于观察取消请求的取消令牌.</param>    /// <returns>创建的异步任务对象.</returns>    private static Task<T> CreateTaskFromAction<T>(Action<TaskCompletionSource<T>> action, CancellationToken cancellationToken)    {        // 验证参数        ArgumentNullException.ThrowIfNull(action, nameof(action));        // 如果令牌已请求取消，立即返回已取消的任务        if (cancellationToken.IsCancellationRequested)        {            return Task.FromCanceled<T>(cancellationToken);        }        // 初始化任务完成源。配置为异步延续，避免调用线程同步执行后续代码导致死锁        var taskCompletionSource = new TaskCompletionSource<T>(TaskCreationOptions.RunContinuationsAsynchronously);        // 注册取消令牌的回调函数。使用 UnsafeRegister 避免不必要的上下文流转，提高性能        var tokenRegistration = cancellationToken.UnsafeRegister(            static (state, token) =>            {                ((TaskCompletionSource<T>)state!).TrySetCanceled(token);            },            taskCompletionSource);        // 任务完成后（无论成功、失败或取消）注销 token 注册，防止内存泄漏        taskCompletionSource.Task.ContinueWith(            static (_, state) =>            {                ((CancellationTokenRegistration)state!).Dispose();            },            tokenRegistration,            CancellationToken.None,            TaskContinuationOptions.ExecuteSynchronously,            TaskScheduler.Default);        try        {            // 执行业务逻辑动作            action(taskCompletionSource);        }        catch (Exception ex)        {            // 捕获同步异常并将其设置到任务源中            taskCompletionSource.TrySetException(ex);        }        return taskCompletionSource.Task;    }}